/**
 * CompetitionUpgradeModal — Renders competition-specific upgrade nudges
 * (rank achievement, XP milestone, streak, founding spots, rank drop).
 *
 * Pairs with useCompetitionUpgrades hook. Does NOT replace SmartUpgradeNudge.
 */
import { useNavigate } from 'react-router-dom';
import { motion, AnimatePresence } from 'framer-motion';
import { apiPost } from '../utils/api';

const ICONS = {
  rank_achievement: '\u{1F3C6}',
  xp_milestone: '\u26A1',
  streak_milestone: '\u{1F525}',
  founding_urgency: '\u23F0',
  rank_drop: '\u{1F4C9}',
};

export default function CompetitionUpgradeModal({ nudge, onDismiss }) {
  const navigate = useNavigate();

  if (!nudge) return null;

  const handleUpgrade = () => {
    // Track click
    apiPost('/analytics/event', {
      event: 'nudge_clicked',
      properties: { type: nudge.type, tier: nudge.tier },
    }).catch(() => {});
    onDismiss();
    navigate('/billing');
  };

  return (
    <AnimatePresence>
      <motion.div
        key="competition-upgrade-backdrop"
        initial={{ opacity: 0 }}
        animate={{ opacity: 1 }}
        exit={{ opacity: 0 }}
        style={{
          position: 'fixed', inset: 0, zIndex: 9999,
          background: 'rgba(0,0,0,0.6)', backdropFilter: 'blur(4px)',
          display: 'flex', alignItems: 'center', justifyContent: 'center',
        }}
        onClick={onDismiss}
      >
        <motion.div
          key="competition-upgrade-card"
          initial={{ scale: 0.9, opacity: 0 }}
          animate={{ scale: 1, opacity: 1 }}
          exit={{ scale: 0.9, opacity: 0 }}
          onClick={e => e.stopPropagation()}
          style={{
            background: '#161B22', border: '1px solid #30363D', borderRadius: 16,
            padding: 32, maxWidth: 420, width: '90%', textAlign: 'center',
          }}
        >
          <div style={{ fontSize: 48, marginBottom: 12 }}>{ICONS[nudge.type] || '\u{1F680}'}</div>
          <h2 style={{ fontSize: 20, fontWeight: 700, color: '#E6EDF3', margin: '0 0 8px' }}>{nudge.title}</h2>
          <p style={{ fontSize: 14, color: '#8B949E', lineHeight: 1.6, margin: '0 0 24px' }}>{nudge.message}</p>

          <button
            onClick={handleUpgrade}
            style={{
              width: '100%', padding: '14px', background: 'linear-gradient(135deg, #58A6FF, #3FB950)',
              border: 'none', borderRadius: 10, color: '#0D1117', fontSize: 16,
              fontWeight: 700, cursor: 'pointer', marginBottom: 12,
            }}
          >
            {nudge.cta}
          </button>

          <button
            onClick={onDismiss}
            style={{
              width: '100%', padding: '10px', background: 'transparent',
              border: '1px solid #30363D', borderRadius: 8, color: '#8B949E',
              fontSize: 13, cursor: 'pointer',
            }}
          >
            Maybe Later
          </button>
        </motion.div>
      </motion.div>
    </AnimatePresence>
  );
}
